	test(7, CMPLXF(90.01, -12.34), CMPLXF(0x1.8f551p+0, -0x1.87dd2ep-10), CMPLXF(0x1.8f5512p+0, -0x1.87dd2cp-10), CMPLXF(0x1.8f5514p+0, -0x1.87dd2ap-10), 0);
	test(8, CMPLXF(-12.34, -12.34), CMPLXF(-0x1.87bd62p+0, -0x1.4b909p-5), CMPLXF(-0x1.87bd6p+0, -0x1.4b908ep-5), CMPLXF(-0x1.87bd5ep+0, -0x1.4b908cp-5), 0);
