	test(15, CMPLXF(nanf(""), nanf("")), CMPLXF(nanf(""), nanf("")), CMPLXF(nanf(""), nanf("")), CMPLXF(nanf(""), nanf("")), 0);
	test(16, CMPLXF(strtof("inf", NULL), nanf("")), CMPLXF(0x1.921fb4p+0, -0x1.0p-149), CMPLXF(0x1.921fb6p+0, 0x0.0p+0), CMPLXF(0x1.921fb8p+0, 0x1.0p-149), 0 | MF_ANYSIGN2);
	test(17, CMPLXF(strtof("-inf", NULL), nanf("")), CMPLXF(-0x1.921fb8p+0, -0x1.0p-149), CMPLXF(-0x1.921fb6p+0, 0x0.0p+0), CMPLXF(-0x1.921fb4p+0, 0x1.0p-149), 0 | MF_ANYSIGN2);
	test(18, CMPLXF(0.0, nanf("")), CMPLXF(nanf(""), nanf("")), CMPLXF(nanf(""), nanf("")), CMPLXF(nanf(""), nanf("")), 0);
