	test(20, CMPLXF(-12.34, strtof("inf", NULL)), CMPLXF(-0x1.921fb8p+0, -0x1.0p-149), CMPLXF(-0x1.921fb6p+0, 0x0.0p+0), CMPLXF(-0x1.921fb4p+0, 0x1.0p-149), 0);
	test(21, CMPLXF(nanf(""), strtof("inf", NULL)), CMPLXF(nanf(""), -0x1.0p-149), CMPLXF(nanf(""), 0x0.0p+0), CMPLXF(nanf(""), 0x1.0p-149), 0);
	test(22, CMPLXF(strtof("inf", NULL), strtof("inf", NULL)), CMPLXF(0x1.921fb4p+0, -0x1.0p-149), CMPLXF(0x1.921fb6p+0, 0x0.0p+0), CMPLXF(0x1.921fb8p+0, 0x1.0p-149), 0);
	test(23, CMPLXF(strtof("-inf", NULL), strtof("inf", NULL)), CMPLXF(-0x1.921fb8p+0, -0x1.0p-149), CMPLXF(-0x1.921fb6p+0, 0x0.0p+0), CMPLXF(-0x1.921fb4p+0, 0x1.0p-149), 0);
	test(24, CMPLXF(0.0, strtof("inf", NULL)), CMPLXF(0x1.921fb4p+0, -0x1.0p-149), CMPLXF(0x1.921fb6p+0, 0x0.0p+0), CMPLXF(0x1.921fb8p+0, 0x1.0p-149), 0);
	test(25, CMPLXF(90.01, strtof("-inf", NULL)), CMPLXF(0x1.921fb4p+0, -0x1.0p-149), CMPLXF(0x1.921fb6p+0, -0x0.0p+0), CMPLXF(0x1.921fb8p+0, 0x1.0p-149), 0);
	test(26, CMPLXF(-12.34, strtof("-inf", NULL)), CMPLXF(-0x1.921fb8p+0, -0x1.0p-149), CMPLXF(-0x1.921fb6p+0, -0x0.0p+0), CMPLXF(-0x1.921fb4p+0, 0x1.0p-149), 0);
	test(27, CMPLXF(nanf(""), strtof("-inf", NULL)), CMPLXF(nanf(""), -0x1.0p-149), CMPLXF(nanf(""), -0x0.0p+0), CMPLXF(nanf(""), 0x1.0p-149), 0);
	test(28, CMPLXF(strtof("inf", NULL), strtof("-inf", NULL)), CMPLXF(0x1.921fb4p+0, -0x1.0p-149), CMPLXF(0x1.921fb6p+0, -0x0.0p+0), CMPLXF(0x1.921fb8p+0, 0x1.0p-149), 0);
	test(29, CMPLXF(strtof("-inf", NULL), strtof("-inf", NULL)), CMPLXF(-0x1.921fb8p+0, -0x1.0p-149), CMPLXF(-0x1.921fb6p+0, -0x0.0p+0), CMPLXF(-0x1.921fb4p+0, 0x1.0p-149), 0);
	test(30, CMPLXF(0.0, strtof("-inf", NULL)), CMPLXF(0x1.921fb4p+0, -0x1.0p-149), CMPLXF(0x1.921fb6p+0, -0x0.0p+0), CMPLXF(0x1.921fb8p+0, 0x1.0p-149), 0);
	test(31, CMPLXF(90.01, 0.0), CMPLXF(0x1.8f47a2p+0, -0x1.0p-149), CMPLXF(0x1.8f47a4p+0, 0x0.0p+0), CMPLXF(0x1.8f47a6p+0, 0x1.0p-149), 0);
	test(32, CMPLXF(-12.34, 0.0), CMPLXF(-0x1.7d6c7p+0, -0x1.0p-149), CMPLXF(-0x1.7d6c6ep+0, 0x0.0p+0), CMPLXF(-0x1.7d6c6cp+0, 0x1.0p-149), 0);
